public struct FfiMeshMessage {
    public var serialized: Data
    public var messageId: String
    public var senderId: String
    public var recipientId: String
    public var hopCount: UInt8
    public var maxHops: UInt8
    /**
     * The encrypted payload bytes from the mesh message envelope.
     * Pass this to decrypt_incoming_message() — NOT the full serialized frame.
     */
    public var payload: Data

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(serialized: Data, messageId: String, senderId: String, recipientId: String, hopCount: UInt8, maxHops: UInt8, 
        /**
         * The encrypted payload bytes from the mesh message envelope.
         * Pass this to decrypt_incoming_message() — NOT the full serialized frame.
         */payload: Data) {
        self.serialized = serialized
        self.messageId = messageId
        self.senderId = senderId
        self.recipientId = recipientId
        self.hopCount = hopCount
        self.maxHops = maxHops
        self.payload = payload
    }
}



extension FfiMeshMessage: Equatable, Hashable {
    public static func ==(lhs: FfiMeshMessage, rhs: FfiMeshMessage) -> Bool {
        if lhs.serialized != rhs.serialized {
            return false
        }
        if lhs.messageId != rhs.messageId {
            return false
        }
        if lhs.senderId != rhs.senderId {
            return false
        }
        if lhs.recipientId != rhs.recipientId {
            return false
        }
        if lhs.hopCount != rhs.hopCount {
            return false
        }
        if lhs.maxHops != rhs.maxHops {
            return false
        }
        if lhs.payload != rhs.payload {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(serialized)
        hasher.combine(messageId)
        hasher.combine(senderId)
        hasher.combine(recipientId)
        hasher.combine(hopCount)
        hasher.combine(maxHops)
        hasher.combine(payload)
    }
}


