public enum FfiRouteDecision {
    
    case deliverLocally
    case forward
    case store
    case dropDuplicate
    case dropExpired
    case dropHopLimit
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeFfiRouteDecision: FfiConverterRustBuffer {
    typealias SwiftType = FfiRouteDecision

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> FfiRouteDecision {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .deliverLocally
        
        case 2: return .forward
        
        case 3: return .store
        
        case 4: return .dropDuplicate
        
        case 5: return .dropExpired
        
        case 6: return .dropHopLimit
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: FfiRouteDecision, into buf: inout [UInt8]) {
        switch value {
        
        
        case .deliverLocally:
            writeInt(&buf, Int32(1))
        
        
        case .forward:
            writeInt(&buf, Int32(2))
        
        
        case .store:
            writeInt(&buf, Int32(3))
        
        
        case .dropDuplicate:
            writeInt(&buf, Int32(4))
        
        
        case .dropExpired:
            writeInt(&buf, Int32(5))
        
        
        case .dropHopLimit:
            writeInt(&buf, Int32(6))
        
        }
    }
}


