 */
public enum FlareError {

    
    
    case CryptoError(msg: String
    )
    case StorageError(msg: String
    )
    case RoutingError(msg: String
    )
    case SerializationError(msg: String
    )
    case InvalidInput(msg: String
    )
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeFlareError: FfiConverterRustBuffer {
    typealias SwiftType = FlareError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> FlareError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .CryptoError(
            msg: try FfiConverterString.read(from: &buf)
            )
        case 2: return .StorageError(
            msg: try FfiConverterString.read(from: &buf)
            )
        case 3: return .RoutingError(
            msg: try FfiConverterString.read(from: &buf)
            )
        case 4: return .SerializationError(
            msg: try FfiConverterString.read(from: &buf)
            )
        case 5: return .InvalidInput(
            msg: try FfiConverterString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: FlareError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case let .CryptoError(msg):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(msg, into: &buf)
            
        
        case let .StorageError(msg):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(msg, into: &buf)
            
        
        case let .RoutingError(msg):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(msg, into: &buf)
            
        
        case let .SerializationError(msg):
            writeInt(&buf, Int32(4))
            FfiConverterString.write(msg, into: &buf)
            
        
        case let .InvalidInput(msg):
            writeInt(&buf, Int32(5))
            FfiConverterString.write(msg, into: &buf)
            
        }
    }
}


